mapper.select:
SELECT oi.orderItemNo, oi.orderNo, oi.prodVariantId, pv.prodNo, p.prodName, p.thumb1FileId, oi.sellerUid, s.companyName AS sellerName, oi.count, p.price AS originalPrice, p.discount AS discountRate, GREATEST((p.price * oi.count) - oi.total, 0) AS discountAmount, oi.price, oi.total, oi.shippingFee, oi.itemStatus, sh.shipmentNo, sh.courierName, sh.trackingNo, sh.status AS shipmentStatus, o.createdAt FROM order_item oi JOIN `order` o ON o.orderNo = oi.orderNo JOIN product_variant pv ON pv.id = oi.prodVariantId JOIN product p ON p.prodNo = pv.prodNo LEFT JOIN seller s ON s.uid = oi.sellerUid LEFT JOIN shipment_item si ON si.orderItemNo = oi.orderItemNo LEFT JOIN shipment sh ON sh.shipmentNo = si.shipmentNo WHERE oi.orderItemNo IN
#{orderItemNo}
ORDER BY oi.orderItemNo ASC

