mapper.insert:
INSERT INTO shipment (
    orderNo, sellerUid, courierName, trackingNo, status, shippedAt, createdAt
) VALUES (
    #{orderNo}, #{sellerUid}, #{courierName}, #{trackingNo}, #{status}, NOW(), NOW()
)

mapper.select:
SELECT oi.orderItemNo, oi.orderNo, o.createdAt, oi.sellerUid, s.companyName AS sellerName, p.prodName AS productName, p.thumb1FileId, oi.count AS quantity, oi.price, oi.total, oi.itemStatus, sh.shipmentNo, sh.courierName, sh.trackingNo, sh.status AS shipmentStatus FROM order_item oi JOIN `order` o ON o.orderNo = oi.orderNo JOIN product_variant pv ON pv.id = oi.prodVariantId JOIN product p ON p.prodNo = pv.prodNo LEFT JOIN seller s ON s.uid = oi.sellerUid LEFT JOIN shipment_item si ON si.orderItemNo = oi.orderItemNo LEFT JOIN shipment sh ON sh.shipmentNo = si.shipmentNo WHERE o.memberUid = #{memberUid}
AND DATE(o.createdAt) >= #{startDate}
AND DATE(o.createdAt) <= #{endDate}
ORDER BY o.createdAt DESC, oi.orderItemNo DESC LIMIT #{limit} OFFSET #{offset}

